119	    -- Synchronizer process
120	    p_outff : process (Out_Clk) is
121	    begin
122	        if rising_edge(Out_Clk) then
123	            -- *** Synchronization ***
124	            -- First two stages
125	            Reg0    <= RegIn;
126	            RegN(0) <= Reg0;
127	
128	            -- Loop through aremaining stages
129	            for i in 1 to RegN'high loop
130	                RegN(i) <= RegN(i - 1);
131	            end loop;
132	
133	            -- *** Reset ***
134	            if Out_Rst = '1' then
135	                Reg0 <= (others => '0');
136	                RegN <= (others => (others => '0'));
137	            end if;
138	        end if;
139	    end process;
