1	---------------------------------------------------------------------------------------------------
2	-- Copyright (c) 2024 by Oliver Bruendler, Switzerland
3	-- Authors: Oliver Bruendler
4	---------------------------------------------------------------------------------------------------
5	
6	---------------------------------------------------------------------------------------------------
7	-- Libraries
8	---------------------------------------------------------------------------------------------------
9	library ieee;
10	    use ieee.std_logic_1164.all;
11	    use ieee.numeric_std.all;
12	
13	library vunit_lib;
14	    context vunit_lib.vunit_context;
15	
16	library work;
17	    use work.olo_test_activity_pkg.all;
18	
19	library olo;
20	
21	---------------------------------------------------------------------------------------------------
22	-- Entity
23	---------------------------------------------------------------------------------------------------
24	-- vunit: run_all_in_same_sim
25	entity olo_base_cc_pulse_tb is
26	    generic (
27	        runner_cfg     : string;
28	        ClockRatio_N_g : integer               := 3;
29	        ClockRatio_D_g : integer               := 2;
30	        SyncStages_g   : positive range 2 to 4 := 2
31	    );
32	end entity;
33	
34	architecture sim of olo_base_cc_pulse_tb is
35	
36	    -----------------------------------------------------------------------------------------------
37	    -- Constants
38	    -----------------------------------------------------------------------------------------------
39	    constant ClockRatio_c : real    := real(ClockRatio_N_g) / real(ClockRatio_D_g);
40	    constant NumPulses_c  : integer := 4;
41	
42	    -----------------------------------------------------------------------------------------------
43	    -- TB Defnitions
44	    -----------------------------------------------------------------------------------------------
45	    constant ClkIn_Frequency_c    : real := 100.0e6;
46	    constant ClkIn_Period_c       : time := (1 sec) / ClkIn_Frequency_c;
47	    constant ClkOut_Frequency_c   : real := ClkIn_Frequency_c * ClockRatio_c;
48	    constant ClkOut_Period_c      : time := (1 sec) / ClkOut_Frequency_c;
49	    constant SlowerClock_Period_c : time := (1 sec) / minimum(ClkIn_Frequency_c, ClkOut_Frequency_c);
50	    constant MaxReactionTime_c    : time := (8 + SyncStages_g)*SlowerClock_Period_c;
51	
52	    -----------------------------------------------------------------------------------------------
53	    -- Interface Signals
54	    -----------------------------------------------------------------------------------------------
55	    signal In_Clk     : std_logic                                  := '0';
56	    signal In_RstIn   : std_logic                                  := '1';
57	    signal In_RstOut  : std_logic;
58	    signal In_Pulse   : std_logic_vector(NumPulses_c - 1 downto 0) := x"0";
59	    signal Out_Clk    : std_logic                                  := '0';
60	    signal Out_RstIn  : std_logic                                  := '1';
61	    signal Out_RstOut : std_logic;
62	    signal Out_Pulse  : std_logic_vector(NumPulses_c - 1 downto 0);
63	
64	begin
65	
66	    -----------------------------------------------------------------------------------------------
67	    -- DUT
68	    -----------------------------------------------------------------------------------------------
69	    i_dut : entity olo.olo_base_cc_pulse
70	        generic map (
71	            NumPulses_g  => NumPulses_c,
72	            SyncStages_g => SyncStages_g
73	        )
74	        port map (
75	            -- Clock Domain A
76	            In_Clk      => In_Clk,
77	            In_RstIn    => In_RstIn,
78	            In_RstOut   => In_RstOut,
79	            In_Pulse    => In_Pulse,
80	            -- Clock Domain B
81	            Out_Clk     => Out_Clk,
82	            Out_RstIn   => Out_RstIn,
83	            Out_RstOut  => Out_RstOut,
84	            Out_Pulse   => Out_Pulse
85	        );
86	
87	    -----------------------------------------------------------------------------------------------
88	    -- Clock
89	    -----------------------------------------------------------------------------------------------
90	    In_Clk  <= not In_Clk after 0.5 * ClkIn_Period_c;
91	    Out_Clk <= not Out_Clk after 0.5 * ClkOut_Period_c;
92	
93	    -----------------------------------------------------------------------------------------------
94	    -- TB Control
95	    -----------------------------------------------------------------------------------------------
96	    -- TB is not very vunit-ish because it is a ported legacy TB
97	    test_runner_watchdog(runner, 1 ms);
98	
99	    p_control : process is
100	        variable v : std_logic_vector(Out_Pulse'range);
101	    begin
102	        test_runner_setup(runner, runner_cfg);
103	
104	        while test_suite loop
105	
106	            -- Reset
107	            In_RstIn  <= '1';
108	            Out_RstIn <= '1';
109	            wait for MaxReactionTime_c;
110	
111	            -- Check if both sides are in reset
112	            check(In_RstOut = '1', "In_RstOut not asserted");
113	            check(Out_RstOut = '1', "Out_RstOut not asserted");
114	
115	            -- Remove reset
116	            wait until rising_edge(In_Clk);
117	            In_RstIn  <= '0';
118	            wait until rising_edge(Out_Clk);
119	            Out_RstIn <= '0';
120	            wait for MaxReactionTime_c;
121	
122	            -- *** Reset Tests ***
123	            if run("Reset") then
124	
125	                -- Check if both sides exited reset
126	                check(In_RstOut = '0', "In_RstOut not de-asserted");
127	                check(Out_RstOut = '0', "Out_RstOut not de-asserted");
128	
129	                -- Check if RstA is propagated to both sides
130	                wait until rising_edge(In_Clk);
131	                In_RstIn <= '1';
132	                wait until rising_edge(In_Clk);
133	                In_RstIn <= '0';
134	                wait for MaxReactionTime_c*2;
135	                check(In_RstOut = '0', "In_RstOut not de-asserted after In_RstIn");
136	                check(Out_RstOut = '0', "Out_RstOut not de-asserted after In_RstIn");
137	                check(In_RstOut'last_event < MaxReactionTime_c*2, "In_RstOut not asserted after In_RstIn");
138	                check(Out_RstOut'last_event < MaxReactionTime_c*2, "Out_RstOut not asserted afterIn_RstIn");
139	
140	                -- Check if RstB is propagated to both sides
141	                wait until rising_edge(Out_Clk);
142	                Out_RstIn <= '1';
143	                wait until rising_edge(Out_Clk);
144	                Out_RstIn <= '0';
145	                wait for MaxReactionTime_c*2;
146	                check(In_RstOut = '0', "In_RstOut not de-asserted after Out_RstIn");
147	                check(Out_RstOut = '0', "Out_RstOut not de-asserted after Out_RstIn");
148	                check(In_RstOut'last_event < MaxReactionTime_c*2, "In_RstOut not asserted after Out_RstIn");
149	                check(Out_RstOut'last_event < MaxReactionTime_c*2, "Out_RstOut not asserted after Out_RstIn");
150	
151	            -- *** Pulse Tests ***
152	            elsif run("Normal-Operation") then
153	
154	                -- single pulse
155	                for idx in 0 to 3 loop
156	                    -- Send pulse
157	                    wait until rising_edge(In_Clk);
158	                    In_Pulse(idx) <= '1';
159	                    wait until rising_edge(In_Clk);
160	                    In_Pulse(idx) <= '0';
161	                    -- Wait for output pulse
162	                    v      := (others => '0');
163	                    v(idx) := '1';
164	                    wait_for_value_stdlv(Out_Pulse, v, 100 us, "Pulse not transferred 1");
165	                    wait until rising_edge(Out_Clk);
166	                    wait until rising_edge(Out_Clk);
167	                    v      := (others => '0');
168	                    check_equal(Out_Pulse, v, "Pulse not removed 1");
169	                end loop;
170	
171	                -- multiple pulses
172	                -- .. in practice pulses could be shifted by one clock cycle but in simulation they are not
173	                -- Send pulse
174	                wait until rising_edge(In_Clk);
175	                In_Pulse <= "0101";
176	                wait until rising_edge(In_Clk);
177	                In_Pulse <= "0000";
178	                -- Wait for output pulse
179	                wait_for_value_stdlv(Out_Pulse, "0101", 100 us, "Pulse not transferred 2");
180	                wait until rising_edge(Out_Clk);
181	                wait until rising_edge(Out_Clk);
182	                v := (others => '0');
183	                check_equal(Out_Pulse, v, "Pulse not removed 2");
184	
185	            -- *** Test if no pulse is transferred after the internal toggle FF is reset by RstIn ***
186	            elsif run("NoPulse-RstIn") then
187	                -- transfer one pulse
188	                pulse_sig(In_Pulse(0), In_Clk);
189	                wait_for_value_stdlv(Out_Pulse, "0001", 100 us, "Pulse not transferred 3");
190	                -- Check if no pulse is produced by RstIn
191	                wait for MaxReactionTime_c;
192	                pulse_sig(In_RstIn, In_Clk);
193	                wait for MaxReactionTime_c;
194	                check_no_activity_stdlv(Out_Pulse, MaxReactionTime_c*2, "Unexpected pulse 3");
195	
196	            -- *** Test if no pulse is transferred after the internal toggle FF is reset by RstOut ***
197	            elsif run("NoPulse-RstOut") then
198	                -- transfer one pulse
199	                pulse_sig(In_Pulse(0), In_Clk);
200	                wait_for_value_stdlv(Out_Pulse, "0001", 100 us, "Pulse not transferred 4");
201	                -- Check if no pulse is produced by RstIn
202	                wait for MaxReactionTime_c;
203	                pulse_sig(Out_RstIn, Out_Clk);
204	                wait for MaxReactionTime_c;
205	                check_no_activity_stdlv(Out_Pulse, MaxReactionTime_c*2, "Unexpected pulse 4");
206	            end if;
207	        end loop;
208	
209	        -- TB done
210	        test_runner_cleanup(runner);
211	    end process;
212	
213	end architecture;
